import{_ as e,o as i,c as s,ak as t}from"./chunks/framework.DsiwUQoa.js";const b=JSON.parse('{"title":"如何给设备刷入Recovery","description":"","frontmatter":{},"headers":[],"relativePath":"Help/FlashRecovery/index.md","filePath":"Help/FlashRecovery/index.md","lastUpdated":1782075627000}'),l={name:"Help/FlashRecovery/index.md"};function o(r,a,h,n,p,d){return i(),s("div",null,[...a[0]||(a[0]=[t('<h1 id="如何给设备刷入recovery" tabindex="-1">如何给设备刷入Recovery <a class="header-anchor" href="#如何给设备刷入recovery" aria-label="Permalink to “如何给设备刷入Recovery”">​</a></h1><h2 id="声明" tabindex="-1">声明 <a class="header-anchor" href="#声明" aria-label="Permalink to “声明”">​</a></h2><p>任何由刷机出现的事故与我无关，请在刷前做好数据备份和原Recovery备份。</p><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to “前言”">​</a></h2><p>Recovery是安卓设备的一个系统分区，可在设备不启动系统的情况下执行基本维护操作。刷入第三方Recovery能解锁更多功能，让你体验更多玩机乐趣。</p><h2 id="准备工作" tabindex="-1">准备工作 <a class="header-anchor" href="#准备工作" aria-label="Permalink to “准备工作”">​</a></h2><h3 id="下载和配置platform-tools" tabindex="-1">下载和配置platform-tools <a class="header-anchor" href="#下载和配置platform-tools" aria-label="Permalink to “下载和配置platform-tools”">​</a></h3><ol><li><p>下载</p><p><a href="https://dl.google.com/android/repository/platform-tools-latest-windows.zip?hl=zh-cn" target="_blank" rel="noreferrer">下载Windows版本</a></p></li><li><p>配置</p><p>将下载的platform-tools解压至C盘根目录</p></li></ol><hr><h3 id="解锁bootloader-简称bl锁" tabindex="-1">解锁Bootloader（简称BL锁） <a class="header-anchor" href="#解锁bootloader-简称bl锁" aria-label="Permalink to “解锁Bootloader（简称BL锁）”">​</a></h3><ol><li>这是最难的一步，现在几乎所有厂商都锁死了BL锁，解锁难如登天。由于不同厂商的BL解锁不同，若以下教程无效，请自行查阅解锁方式。</li></ol><h4 id="将设备重启至fastboot模式" tabindex="-1">将设备重启至Fastboot模式 <a class="header-anchor" href="#将设备重启至fastboot模式" aria-label="Permalink to “将设备重启至Fastboot模式”">​</a></h4><ol><li>将设备关机，然后按住音量-键和电源键，设备震动或屏幕亮起后，松开电源键，这样即可进入Fastboot模式</li></ol><h4 id="将设备连接到电脑" tabindex="-1">将设备连接到电脑 <a class="header-anchor" href="#将设备连接到电脑" aria-label="Permalink to “将设备连接到电脑”">​</a></h4><ol><li><p>使用优质的数据线将设备连接至电脑</p></li><li><p>在电脑上打开CMD</p></li><li><p>以下命令并回车</p><div class="language-txt"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>cd C:\\platform-tools</span></span></code></pre></div></li><li><p>若正常反馈，则输入</p><div class="language-txt"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>fastboot devices</span></span></code></pre></div></li><li><p>若显示设备序列号，则输入以下命令并回车</p><div class="language-txt"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>fastboot oem unlock</span></span></code></pre></div></li><li><p>若解锁失败，则尝试</p><div class="language-txt"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>fastboot flashing unlock</span></span></code></pre></div></li><li><p>若仍然解锁失败，请自行查询解锁方式</p></li></ol><h3 id="下载recovery" tabindex="-1">下载Recovery <a class="header-anchor" href="#下载recovery" aria-label="Permalink to “下载Recovery”">​</a></h3><ol><li>前往<a href="https://twrp.me/Devices/" target="_blank" rel="noreferrer">TWRP官网</a>或<a href="https://orangefox.download/" target="_blank" rel="noreferrer">OrangeFox官网</a>下载Recovery</li><li>如果下载的是一个压缩包，请解压它，并把里面的recovery.img复制到C盘根目录。如果下载的直接是个recovery.img，请把它复制到C盘根目录</li></ol><h2 id="正式刷入" tabindex="-1">正式刷入 <a class="header-anchor" href="#正式刷入" aria-label="Permalink to “正式刷入”">​</a></h2><ol><li><p>打开CMD</p></li><li><p>输入以下命令并回车</p><div class="language-txt"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>cd C:\\platform-tools</span></span></code></pre></div></li><li><p>若正常切换，则输入以下命令并回车</p><div class="language-txt"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>fastboot devices</span></span></code></pre></div></li><li><p>若显示了设备ID，则输入</p><div class="language-txt"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>fastboot flash recovery C:/recovery.img</span></span></code></pre></div></li><li><p>刷入成功后输入以下命令重启到recovery模式</p><div class="language-txt"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>fastboot reboot recovery</span></span></code></pre></div></li></ol>',19)])])}const g=e(l,[["render",o]]);export{b as __pageData,g as default};
